    customer: '',
    phone: '',
    items: 1,
    total: '',
    status: 'pending'
  });

  const triggerSuccess = () => {
    setIsSuccessOpen(true);
    confetti({
      particleCount: 150,
      spread: 70,
      origin: { y: 0.6 },
      colors: ['#6366f1', '#10b981', '#f59e0b']
    });
    setTimeout(() => setIsSuccessOpen(false), 3000);
  };

  const openWhatsApp = (orderId: string, phone: string) => {
     const message = encodeURIComponent(`Hello, I'm contacting you from your store regarding order ${orderId}.`);
     window.open(`https://wa.me/${phone.replace('+', '')}?text=${message}`, '_blank');
  };

  const createOrder = () => {
    if (!newOrder.customer) return;
    const orderId = `ORD-${Math.floor(Math.random() * 90000) + 10000}`;
    const date = new Date().toLocaleString();
    setOrders([{ id: orderId, ...newOrder, date, total: `$${parseFloat(newOrder.total).toFixed(2)}` }, ...orders]);
    setIsModalOpen(false);
    setNewOrder({ customer: '', phone: '', items: 1, total: '', status: 'pending' });
    triggerSuccess();
  };

  const updateStatus = (status: string) => {
     if (!activeOrderId) return;
     setOrders(orders.map(o => o.id === activeOrderId ? { ...o, status } : o));
     setIsStatusPickerOpen(false);
     setActiveOrderId(null);
     triggerSuccess();
  };

  const exportOrdersToCSV = () => {
    // CSV Header row
    const headers = ['Order ID', 'Customer', 'Phone', 'Status', 'Total', 'Date', 'Items'];
    // Order data rows
    const rows = orders.map(o => [
      o.id, 
      o.customer, 
      o.phone.replace(',', ' '), // Avoid comma conflicts in CSV
      o.status.toUpperCase(), 
      o.total.replace('$', '').replace(',', ''), 
      o.date.replace(',', ' '), 
      o.items
    ]);

    // Combine to single string
    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(','), ...rows.map(r => r.join(','))].join("\n");

    // Launch download sequence
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `ProOMS_Orders_${new Date().toISOString().split('T')[1]?.split('.')[0] || 'REPORT'}.csv`);
